var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"CCN No. BDM003M000027-03\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 진술","JPN":"CCN No. BDM003M000027-03\\n<color=#ffd34c>1級要因</color> 閲覧承認資料\\n付録: 対象者陳述","ENG":"CCN No. BDM003M000027-03\\n<color=#ffd34c>Class 1 Entity</color> Viewing Approval Document\\nAppendix: Subject Testimony","TWN":"(TWN)CCN No. BDM003M000027-03\\n<color=#ffd34c>1급 요인</color> 열람 승인 자료\\n부록: 대상자 진술"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"인터뷰는 이상입니다. 이후 행적에 대한 증언은 주관적인 판단의 비중이 높아 편집되었습니다.","JPN":"インタビューは以上です。以後行跡に対する証言は主観的な判断の比重が高くて編集されました。","ENG":"The interview is abnormal. Testimony regarding subsequent actions has been edited due to high subjectivity.","TWN":"(TWN)인터뷰는 이상입니다. 이후 행적에 대한 증언은 주관적인 판단의 비중이 높아 편집되었습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"조디악 나이츠?","JPN":"チョディアックナイツ?","ENG":"Zodiac Knights?","TWN":"(TWN)조디악 나이츠?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 인터뷰에서 언급했듯이 업계에서는 꽤 유명합니다.","JPN":"はい。インタビューで言及したように業界ではかなり有名です。","ENG":"Yes. As mentioned in the interview, they're quite famous in the industry.","TWN":"(TWN)네. 인터뷰에서 언급했듯이 업계에서는 꽤 유명합니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"무상으로 침식체 토벌을 하는 코스튬 플레이어들로 말이죠.","JPN":"無償で侵食体討伐をするコスチュームプレイヤーで言葉ですよ。","ENG":"Those costume players who hunt erosion creatures for free, that is.","TWN":"(TWN)무상으로 침식체 토벌을 하는 코스튬 플레이어들로 말이죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"무상으로 말인가? 요즘 시대에?","JPN":"無償で言葉であるか?最近時代に?","ENG":"For free? In this day and age?","TWN":"(TWN)무상으로 말인가? 요즘 시대에?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"네. 상황 따지지 않고 뛰어든다더군요.","JPN":"はい。状況問わずに跳び込むと言いますね。","ENG":"Yes. They rush in without considering the situation.","TWN":"(TWN)네. 상황 따지지 않고 뛰어든다더군요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"덕분에 프리랜서들 사이에선 불구대천의 원수 취급을 받고 있습니다. 원한으로 사람을 죽일 수 있으면 골백 번은 죽었겠죠.","JPN":"おかげでフリーランサーの間では不倶戴天の原水取り扱いを受けています。恨みで人を殺すことができればゴールバッグ回は死にます。","ENG":"Thanks to that, they're treated as mortal enemies among freelancers. If resentment could kill, they'd have died a hundred times over.","TWN":"(TWN)덕분에 프리랜서들 사이에선 불구대천의 원수 취급을 받고 있습니다. 원한으로 사람을 죽일 수 있으면 골백 번은 죽었겠죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"흠.......","JPN":"傷.......","ENG":"Hmm.......","TWN":"(TWN)흠......."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"세계평화니 어쩌니 하던데, 그건 또 무슨 얘기인가?","JPN":"世界平和だのどうするからしていたが、それはまた何の話であるか?","ENG":"They were going on about world peace and such, but what is that about?","TWN":"(TWN)세계평화니 어쩌니 하던데, 그건 또 무슨 얘기인가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"노블레스 오블리주의 일종입니다.","JPN":"ノブレス・オブリージュの一種です。","ENG":"It's a type of noblesse oblige.","TWN":"(TWN)노블레스 오블리주의 일종입니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"이면세계에 대항할 힘을 얻었으니 현실을 보호하기 위해 헌신하겠다, 그런 뜻으로 추정됩니다.","JPN":"カウンターサイドに対抗する力を得たから現実を保護するために献身する、そんな意味で推定されます。","ENG":"Having gained power to oppose the Netherworld, they devote themselves to protecting reality—that is the presumed intent.","TWN":"(TWN)이면세계에 대항할 힘을 얻었으니 현실을 보호하기 위해 헌신하겠다, 그런 뜻으로 추정됩니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"방법론에 있어서는 내부에서도 의견이 나뉘는 모양입니다만.","JPN":"方法論においては内部でも意見が分けられる形ですが。","ENG":"Regarding their defensive capabilities, opinions seem to be divided even internally, however.","TWN":"(TWN)방법론에 있어서는 내부에서도 의견이 나뉘는 모양입니다만."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네 기준으로 실력을 평가하면 어느 정도 수준인가.","JPN":"君の基準で実力を評価すればどれくらい水準か。","ENG":"By your standards, what level would you assess their skills at?","TWN":"(TWN)자네 기준으로 실력을 평가하면 어느 정도 수준인가."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"좋지도 나쁘지도 않습니다. 굳이 딱 잘라 얘기한다면 나쁜 쪽이네요.","JPN":"良くも悪くありません。敢えてきっぱり話したら悪い側ですね。","ENG":"Neither good nor bad. If forced to give a definitive answer, they're on the poor side.","TWN":"(TWN)좋지도 나쁘지도 않습니다. 굳이 딱 잘라 얘기한다면 나쁜 쪽이네요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"목숨을 내던지더라도 사람들을 지키려는 자세....\\n도의적으로 훌륭할진 몰라도 중요 전력에게 원하는 바는 아닙니다.","JPN":"命を投げ出しても人々を守ろうとする姿勢....\\n道義的に立派かも知れなくても重要電力に願うところではないです。","ENG":"The attitude of trying to protect people even at the cost of their lives... While it may be morally admirable, it's not what you want from key combat assets.","TWN":"(TWN)목숨을 내던지더라도 사람들을 지키려는 자세....\\n도의적으로 훌륭할진 몰라도 중요 전력에게 원하는 바는 아닙니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"만약 그러다가 정말 희생이라도 했다간 손해가 막심하니까요.","JPN":"もしそうするうちに本当に犠牲でもしたら損害が甚だしいからです。","ENG":"Because if they actually end up sacrificing themselves, the loss would be immense.","TWN":"(TWN)만약 그러다가 정말 희생이라도 했다간 손해가 막심하니까요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"저희가 치르는 전쟁은 한두 명의 숭고한 희생으로 뒤집을 수도 없고, 장병들의 사기가 오른다고 유리해지지도 않습니다.","JPN":"私どもが支払う戦争は一、二人の崇高な犠牲で覆すこともできなくて、将兵の士気が上がると有利にならないです。","ENG":"The war we fight cannot be overturned by the noble sacrifice of one or two individuals, nor does it become advantageous simply because troop morale rises.","TWN":"(TWN)저희가 치르는 전쟁은 한두 명의 숭고한 희생으로 뒤집을 수도 없고, 장병들의 사기가 오른다고 유리해지지도 않습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"자네도 꽤 날카롭게 반응하는군 그래.","JPN":"君もかなり鋭く応じるねそう。","ENG":"You react quite sharply, I see.","TWN":"(TWN)자네도 꽤 날카롭게 반응하는군 그래."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"옛 시절이 떠올라서 그러는 건가?","JPN":"昔の時代が浮び上がってそんな濃いか?","ENG":"Is it because you're reminded of the old days?","TWN":"(TWN)옛 시절이 떠올라서 그러는 건가?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"전황을 바라보는 통찰력이 성장한 거라고 해 주시죠.","JPN":"戦況を眺める洞察力が成長したことと言ってくれます。","ENG":"Please say it's because my insight into the war situation has grown.","TWN":"(TWN)전황을 바라보는 통찰력이 성장한 거라고 해 주시죠."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그래. 자네나 나나 이제 뒷짐 지고 먼발치에서 지켜봐야 할 입장이니 말일세. ","JPN":"そう。君やナナもう後手に組んで少し離れた所で見守らなければならない立場だから言葉だよ。","ENG":"Indeed. Both you and I are now in positions where we must stand back and watch from the sidelines.","TWN":"(TWN)그래. 자네나 나나 이제 뒷짐 지고 먼발치에서 지켜봐야 할 입장이니 말일세. "},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그러기 싫어서 지금 이러고 계시지 않습니까.","JPN":"そうしたくなくて今こうしていらっしゃらないですか。","ENG":"Isn't that exactly why you're doing what you're doing now?","TWN":"(TWN)그러기 싫어서 지금 이러고 계시지 않습니까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"가끔은 외유가 필요할 때도 있는 거지.","JPN":"たまには外遊が必要な時もあるホームレス。","ENG":"Sometimes you need to stretch your legs.","TWN":"(TWN)가끔은 외유가 필요할 때도 있는 거지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"어쨌거나 지시한 대로 조사해 줘서 고맙네. 이걸로 확인해 볼 건수가 생겼군.","JPN":"とにかく指示したとおり調査してくれてありがたいね。これに確認してみる件数が生じたな。","ENG":"Anyway, thank you for investigating as instructed. This has given us something worth looking into.","TWN":"(TWN)어쨌거나 지시한 대로 조사해 줘서 고맙네. 이걸로 확인해 볼 건수가 생겼군."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"█████과의 연관성 말씀이신가요.","JPN":"█████科の関連性お話ですか。","ENG":"Are you referring to the connection with [REDACTED]?","TWN":"(TWN)█████과의 연관성 말씀이신가요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그렇지. 이런 집단이 하루 아침에 하늘에서 뚝 떨어지진 않아. 만약 그렇다면 여기가 이면세계겠지.","JPN":"そうなの。このような集団が一瞬に空から全く離れない。もしそれならばここがカウンターサイドだろう。","ENG":"Exactly. Such a group doesn't just fall from the sky overnight. If that were the case, this would be the Netherworld.","TWN":"(TWN)그렇지. 이런 집단이 하루 아침에 하늘에서 뚝 떨어지진 않아. 만약 그렇다면 여기가 이면세계겠지."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하지만 흥미롭군. 대의가 어쩌느니 점잔 빼던 양반들이 왜 이런 방법을 택한 걸까.","JPN":"しかしおもしろいね。大義がどうするより気取った両班がなぜこのような方法を選んだのか。","ENG":"But it's intriguing. Why would those gentlemen who used to put on airs about grand causes choose such a method?","TWN":"(TWN)하지만 흥미롭군. 대의가 어쩌느니 점잔 빼던 양반들이 왜 이런 방법을 택한 걸까."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그만큼 그쪽도 절박하다는 암시 아닐까요?","JPN":"それほどそちらも切迫するという暗示ではないでしょうか?","ENG":"Could it be a sign that they are just as desperate?","TWN":"(TWN)그만큼 그쪽도 절박하다는 암시 아닐까요?"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"뭐.... 자네 말대로라면 더 바랄 나위가 없네만.","JPN":"何....君の言葉通りならさらに望むナ上がないねだけ。","ENG":"Well.... If it's as you say, I couldn't ask for more.","TWN":"(TWN)뭐.... 자네 말대로라면 더 바랄 나위가 없네만."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"백지는 먹물 한 방울로도 더럽혀지는 법이지. 순수한 의도라는 건 오래 이어지지 못해.","JPN":"白紙は墨汁一滴でも汚くなるものである。純粋な意図ということは長く続くことができない。","ENG":"A blank sheet is stained by even a single drop of ink. Pure intentions cannot last long.","TWN":"(TWN)백지는 먹물 한 방울로도 더럽혀지는 법이지. 순수한 의도라는 건 오래 이어지지 못해."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"다른 기사단원들도 조사를 시작해 주게.","JPN":"他の騎士団員も調査を始めてくれ。","ENG":"Have the other knights investigated as well.","TWN":"(TWN)다른 기사단원들도 조사를 시작해 주게."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"예. 그럼 항상 사용하던 채널로.","JPN":"はい。それでは常に使ったチャンネル路。","ENG":"Yes. Then through the usual channel.","TWN":"(TWN)예. 그럼 항상 사용하던 채널로."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}}]`);export{e as default};